import jetbrains.mps.baselanguage.unitTest.execution.launcher.TestExecutor;
import jetbrains.mps.logging.Logger;
import org.junit.runner.notification.RunListener;
import org.junit.runner.Request;
import org.junit.runner.JUnitCore;
import java.io.PrintStream;
import org.junit.runner.Result;
import org.jetbrains.annotations.Nullable;
import org.jetbrains.annotations.NotNull;
import org.junit.runner.notification.StoppedByUserException;

public abstract class AbstractJUnitTestMixin implements TestExecutor {
  private static final Logger LOG = Logger.getLogger(AbstractJUnitTestMixin.class);

  private final boolean myRedirectStdOutErr;
  protected CommandOutputStream myOutStream;
  protected CommandOutputStream myErrStream;

  private RunListener myListener;
  private volatile boolean myStopping = false;
  private StoppableRunner myCurrentRunner = null;
  protected int myFailureCount = -1;
  private Throwable myException;

  public AbstractJUnitTestMixin(boolean redirectStdOutErr) {
    this.myRedirectStdOutErr = redirectStdOutErr;
  }

  @Override
  public void execute() {
    myFailureCount = 0;
    try {
      executeSafe();

    } catch (Throwable t) {
      // XXX myFailureCount may get invalid if exception is thrown from core.run
      processThrowable(t);
    }
  }

  protected abstract void executeSafe() throws Throwable;

  protected void executeWithJunit4(Iterable<Request> requests) throws Throwable {
    JUnitCore jUnitCore = prepareJUnitCore(requests);
    doExecute(jUnitCore, requests);
    if (myListener != null) {
      // no real reason, just it's nice to clean up after yourself
      jUnitCore.removeListener(myListener);
    }
  }

  @Override
  public void init() {
    if (LOG.isDebugLevel()) {
      LOG.debug("Initializing " + getClass().getSimpleName());
    }
    myOutStream = new CommandOutputStream(System.out);
    myErrStream = new CommandOutputStream(System.err);
    if (myRedirectStdOutErr) {
      System.setOut(new PrintStream(myOutStream));
      System.setErr(new PrintStream(myErrStream));
    }
  }

  @Override
  public void dispose() {
    if (myRedirectStdOutErr) {
      System.setOut(myOutStream.getOldStream());
      System.setErr(myErrStream.getOldStream());
    }
    if (LOG.isDebugLevel()) {
      LOG.debug("Disposing " + getClass().getSimpleName());
    }
  }

  @Override
  public int getFailureCount() {
    return myFailureCount;
  }

  @Override
  public Throwable getExecutionError() {
    return myException;
  }

  public void stopRun() {
    StoppableRunner currentRunner = this.getCurrentRunner();
    if (currentRunner != null) {
      currentRunner.pleaseStop();
    } else {
      if (LOG.isWarningLevel()) {
        LOG.warning("the current runner is not initialized yet which might indicate that the run has not started yet.");
      }
    }
    myStopping = true;
  }

  private JUnitCore prepareJUnitCore(Iterable<Request> requests) {
    JUnitCore core = new JUnitCore();
    myListener = createListener(requests);
    core.addListener(myListener);
    return core;
  }

  private void doExecute(JUnitCore core, Iterable<Request> requests) throws Throwable {
    for (Request request : requests) {
      updateRunner(request);
      Result res = core.run(myCurrentRunner);
      myFailureCount += res.getFailureCount();
    }
  }

  @Nullable
  private StoppableRunner getCurrentRunner() {
    return myCurrentRunner;
  }

  private void updateRunner(Request request) {
    myCurrentRunner = new StoppableRunner(request, myStopping);
  }

  @NotNull
  private RunListener createListener(Iterable<Request> requests) {
    return new DefaultRunListener(myOutStream);
  }

  protected void processThrowable(Throwable t) {
    if (!(t instanceof StoppedByUserException)) {
      // StoppedByUserException means external intention to stop tests, no reason to log
      myException = t;
      if (LOG.isErrorLevel()) {
        LOG.error("Exception in the test framework", t);
      }
    }
  }
}
